var e=[{id:`L3_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`<color=#ffd34c>코핀 컴퍼니 부사장 이수연입니다.</color>`,JPN:`<color=#ffd34c>コフィンカンパニー副社長のカナミ・キズナです。</color>`,ENG:`<color=#ffd34c>You've reached Vice President Lee Sooyeon of Coffin Company.</color>`,TWN:`<color=#ffd34c>我是科芬公司副總 李秀妍。</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LEESOOYEON_COFFIN_NULL_NULL`,text:{KOREA:`<color=#ffd34c>지금은 연락을 받을 수 없으니 음성 메시지를 남겨 주십시오.</color>`,JPN:`<color=#ffd34c>只今不在にしておりますので、発信音の後にお名前とご用件をお話しください。</color>`,ENG:`<color=#ffd34c>I am unable to come to the phone right now. Please leave a message.</color>`,TWN:`<color=#ffd34c>現在無法通話，請留下語音訊息。</color>`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`윌버에 대한 정보를 언제 수령할 수 있을지 알고 싶습니다. 휴먼.`,JPN:`ウィルバーに関する情報をいつもらえるか知りたいです、ヒューマン。`,ENG:`I'd like to know if you have any updates on Wilbur. Human.`,TWN:`人類，我想知道什麼時候可以收到韋爾伯的資訊。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`이번이 13,740,266회째 수신 미확인된 메시지로 남지 않길 바랍니다.`,JPN:`今回が13,740,266回目の受信未確認メッセージとして残らないことを祈ります。`,ENG:`I hope this won't be just the 13,740,266th unchecked message.`,TWN:`希望這不是第13,740,266次未回覆的訊息。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`30초 후 다시 연락드리겠습니다. 이상.`,JPN:`30秒後にまたご連絡いたします、以上。`,ENG:`I'll contact you again in 30 seconds. Over and out.`,TWN:`30秒後我會再打來，以上。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`미안합니다. 대시, 리타.`,JPN:`ごめんなさい。ダッシュ、リタ。`,ENG:`I'm sorry, Dash and Rita.`,TWN:`抱歉，黛西、麗塔。`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`이면세계를 수색하는 동안 제 정보망이 상당 부분 훼손되었더군요.`,JPN:`裏世界を捜索する間に、私の情報網の相当部分が破損してしまいました。`,ENG:`Searching the Counterside had significantly damaged my information network.`,TWN:`搜查異界的時候，我的情報網有部分毀損。`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L14_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`윌버의 행방을 알아내기 위해서는……. 지원이 필요합니다.`,JPN:`ウィルバーの行方を突き止めるためには……サポートが必要です。`,ENG:`In order to locate Wilbur… I will need help.`,TWN:`要想找到韋爾伯的下落……就需要支援。`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`확실히 혼자로 돌아오니 예전처럼 일이 풀리지 않는군요.`,JPN:`一人になってからは、前のようにうまくいきませんね。`,ENG:`Things certainly haven't been as easy as they were now that I'm alone again.`,TWN:`確實是就算一個人回到這裡，也無法像以前一樣解決事情`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L17_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`그러니 가능하다면 돌아와 주십시오. 월급을 200% 인상해 드리겠습니다.`,JPN:`だから可能でしたら帰ってきてください。給料を200％引き上げます。`,ENG:`So please come back, if it's at all possible. I will double your salaries.`,TWN:`可以的話，請你們回來吧。我可以幫你們加薪200%。`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L19_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`……불가능하겠지만요.`,JPN:`……不可能だとは思いますが。`,ENG:`…Though I doubt that is possible.`,TWN:`……根本不可能吧。`},stage:{bg:`HORIZON_01_B`,slots:{L:null,C:null,R:null}}},{id:`L21_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>주간고속도로 제 5호선 상의 폭발음 감지.</color>`,JPN:`<color=#ffd34c>州間高速道路第5号線から爆発音を感知。</color>`,ENG:`<color=#ffd34c>Explosion detected on the 5th Interstate Highway.</color>`,TWN:`<color=#ffd34c>感應到州間高速公路5號線上的爆炸聲響。</color>`},stage:{bg:`OFFICE_DETECT`,slots:{L:null,C:null,R:null}}},{id:`L22_1`,type:`dialog`,speaker:null,text:{KOREA:`<color=#ffd34c>샘플 분석 결과, 교전 발생 가능성 높음.</color>`,JPN:`<color=#ffd34c>サンプル分析の結果、交戦発生の可能性大。</color>`,ENG:`<color=#ffd34c>Sample analysis suggest engagement is highly likely.</color>`,TWN:`<color=#ffd34c>樣本分析結果，發生衝突的可能性很高。</color>`},stage:{bg:`OFFICE_DETECT`,slots:{L:null,C:null,R:null}}},{id:`L25_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`…….`,TWN:`……`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L27_1`,type:`dialog`,speaker:`RACHEL_NPC_NULL_NULL`,text:{KOREA:`내일 엠마 데려다 줄 때 같이 가겠다고 해. 그렇게 말하면 저래도 하룻밤은 재워 줄 거야.`,JPN:`明日エマを病院に連れて行く時、一緒に行きたいって言って。そう言えば最低でも一晩は泊めてくれると思う。`,ENG:`Tell him you'd like to tag along when we take Emma to the hospital tomorrow. If you do that, he'll let you stay, at least for the night.`,TWN:`說你明天也想一起送愛瑪去醫院！院長聽到你那麼說，起碼會收留你一晚吧！`},stage:{bg:`BACKSTREET2`,slots:{L:null,C:{char_id:`RACHEL_NPC_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`HORIZON_HORIZON_NULL_NULL`,text:{KOREA:`……소음 공해가 너무 심하군요.`,JPN:`……騒音公害がひどいですね。`,ENG:`…There is far too much noise.`,TWN:`……噪音汙染有點嚴重呢。`},stage:{bg:`OFFICE_DETECT`,slots:{L:null,C:{char_id:`HORIZON_HORIZON_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};